def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 15):
            if ratio < 0.03 * j:
                score += (15 - j) * np.exp(-ratio * j * 3) + np.sin(ratio * np.pi * j * 1.5)
            elif 0.03 * j <= ratio < 0.25:
                score += (j ** 4) * np.cos(ratio * np.pi * j / 1.5) - np.log1p(ratio * j * 2)
            else:
                score += np.sqrt(ratio * j) * np.tanh(j / (ratio + 0.05))
        leftover_ratio = (capacity - item) / capacity
        if leftover_ratio < 0.02:
            score *= 4
            for k in range(1, 7):
                if leftover_ratio < 0.005 * k:
                    score += k * np.exp(-k * ratio * 1.5) + np.cos(k * np.pi * ratio)
        elif leftover_ratio < 0.1:
            score *= 2
            for m in range(1, 4):
                score += np.log1p(m * ratio * 1.5) * np.sin(m * np.pi * ratio * 1.2) - m * 0.1
        else:
            for n in range(1, 8):
                if leftover_ratio > 0.2 * n:
                    score += n * np.sqrt(item / capacity) * np.cos(n * ratio * 1.3) - n * 0.05
                else:
                    score -= n * np.exp(-ratio * n * 1.2) + np.sin(n * np.pi * ratio / 2)
        if ratio > 0.65:
            score += np.tanh(ratio * 6) * 10
            if capacity < item * 1.05:
                score *= 2.2
        if ratio < 0.1:
            for p in range(1, 5):
                score += p * np.exp(-p * ratio) * np.cos(p * np.pi * ratio * 2)
        if score < 0:
            score = abs(score) * 0.6 + np.log1p(item) * 1.2
        if np.isnan(score) or np.isinf(score):
            score = 0
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        max_priority = 1
    else:
        max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if priorities[i] == np.inf:
            priorities[i] = max_priority * 5
    return priorities
